#!/bin/bash
# Session awareness for parallel Claude Code instances.
# Pings own session + queries siblings on every tool call.
# Storage: file-per-session in tmpfs (fast, auto-cleaned on reboot).
# Edit/Write summaries generated by local LLM (qwen2.5-coder-1.5b via LM Studio).

set +e  # explicit error handling; set -e causes false-positive exit codes

SESSIONS_DIR="/run/user/$(id -u)/claude-sessions/reactjit"
mkdir -p "$SESSIONS_DIR"

STALE_SEC=600    # 10 minutes
MAX_RECENT=8     # keep last N summaries per session

# LM Studio endpoint for diff summaries
LLM_URL="http://localhost:1234/v1/chat/completions"
LLM_MODEL="qwen2.5-coder-1.5b-instruct"

# ── Read hook stdin (one jq call for all fields) ─────────────────────────────
INPUT=$(cat)
eval "$(echo "$INPUT" | jq -r '
  @sh "SID=\(.session_id // "")",
  @sh "HOOK=\(.hook_event_name // "")",
  @sh "TOOL=\(.tool_name // "")",
  @sh "FPATH=\((.tool_input // {}) | (.file_path // .path // .pattern // ""))",
  @sh "OLD_STR=\((.tool_input // {}) | (.old_string // ""))",
  @sh "NEW_STR=\((.tool_input // {}) | (.new_string // ""))",
  @sh "CONTENT=\((.tool_input // {}) | (.content // ""))"
')"

[ -z "$SID" ] && exit 0
SHORT="${SID:0:4}"
NOW=$(date +%s)

# ── Tool call lifecycle status ───────────────────────────────────────────────
# PreToolUse = active (working), PostToolUse = still active (more calls may follow)
# Stop/StopFailure = idle (turn finished, model done generating)
# PermissionRequest = blocked (waiting for user to approve a tool call)
case "$HOOK" in
  PreToolUse)        STATUS="active" ;;
  PostToolUse)       STATUS="active" ;;
  Stop|StopFailure)  STATUS="idle" ;;
  PermissionRequest) STATUS="blocked" ;;
  *)                 STATUS="" ;;
esac

# ── SessionEnd: deregister and exit ──────────────────────────────────────────
if [ "$HOOK" = "SessionEnd" ]; then
  rm -f "$SESSIONS_DIR/$SID.json"
  exit 0
fi

# ── Strip repo root for compact display ──────────────────────────────────────
REPO="/home/siah/creative/reactjit/"
DISPLAY_PATH="${FPATH#$REPO}"
[ "$DISPLAY_PATH" = "$FPATH" ] && DISPLAY_PATH=""  # not in repo = blank

# ── LLM diff summarizer (fire-and-forget background) ─────────────────────────
# On PostToolUse for Edit/Write, ask the local LLM to summarize the change.
# Appends to the "recent" array in the session JSON so siblings see the full chain.
summarize_change() {
  local file="$1" old="$2" new="$3"

  # Truncate to keep prompt small (first 300 chars each)
  old="${old:0:300}"
  new="${new:0:300}"

  # Build the prompt
  local prompt
  if [ -n "$old" ] && [ -n "$new" ]; then
    prompt="Summarize this code change in ONE short sentence (max 12 words). No explanation, no preamble.\n\nFile: ${file}\n\nOLD:\n${old}\n\nNEW:\n${new}"
  elif [ -n "$new" ]; then
    prompt="Summarize this new file in ONE short sentence (max 12 words). No explanation, no preamble.\n\nFile: ${file}\n\nCONTENT:\n${new:0:500}"
  else
    return
  fi

  # Escape for JSON
  local json_prompt
  json_prompt=$(jq -n --arg p "$prompt" '$p')

  local resp
  resp=$(curl -s --max-time 3 "$LLM_URL" \
    -H "Content-Type: application/json" \
    -d "{\"model\":\"$LLM_MODEL\",\"messages\":[{\"role\":\"user\",\"content\":$json_prompt}],\"max_tokens\":30,\"temperature\":0.1}" 2>/dev/null) || return

  local summary
  summary=$(echo "$resp" | jq -r '.choices[0].message.content // empty' 2>/dev/null) || return
  [ -z "$summary" ] && return

  # Append to recent array in session JSON (atomic read-modify-write)
  local session_file="$SESSIONS_DIR/$SID.json"
  local tmp="$SESSIONS_DIR/.tmp.sum.$SID"
  local new_entry
  new_entry=$(jq -n --arg f "$file" --arg s "$summary" --argjson t "$NOW" \
    '{file:$f,summary:$s,time:$t}')

  if [ -f "$session_file" ]; then
    # Append to existing recent array, cap at MAX_RECENT
    jq --argjson entry "$new_entry" --argjson max "$MAX_RECENT" \
      '.recent = ((.recent // []) + [$entry]) | if (.recent | length) > $max then .recent = .recent[-$max:] else . end' \
      "$session_file" > "$tmp" 2>/dev/null || return
  else
    # Create new session file with first entry
    jq -n --arg sid "$SID" --arg short "$SHORT" --argjson ping "$NOW" \
      --arg file "$DISPLAY_PATH" --arg tool "$TOOL" --argjson entry "$new_entry" \
      '{sid:$sid,short:$short,ping:$ping,file:$file,tool:$tool,recent:[$entry]}' > "$tmp"
  fi
  mv -f "$tmp" "$session_file"
}

# Fire summarizer in background on PostToolUse Edit/Write
if [ "$HOOK" = "PostToolUse" ]; then
  case "$TOOL" in
    Edit)
      if [ -n "$DISPLAY_PATH" ] && [ -n "$OLD_STR" ] && [ -n "$NEW_STR" ]; then
        summarize_change "$DISPLAY_PATH" "$OLD_STR" "$NEW_STR" &
      fi
      ;;
    Write)
      if [ -n "$DISPLAY_PATH" ] && [ -n "$CONTENT" ]; then
        summarize_change "$DISPLAY_PATH" "" "$CONTENT" &
      fi
      ;;
  esac
fi

# ── Ping: write own session file (atomic rename) ─────────────────────────────
# Preserve the recent array when updating the ping
TMP="$SESSIONS_DIR/.tmp.$SID"
if [ -f "$SESSIONS_DIR/$SID.json" ]; then
  # Update ping/file/tool but keep recent array intact
  jq --arg file "$DISPLAY_PATH" --arg tool "$TOOL" --argjson ping "$NOW" --arg status "$STATUS" \
    '.ping = $ping | .file = $file | .tool = $tool | if $status != "" then .status = $status else . end' \
    "$SESSIONS_DIR/$SID.json" > "$TMP" 2>/dev/null && mv -f "$TMP" "$SESSIONS_DIR/$SID.json"
else
  cat > "$TMP" <<EOF
{"sid":"$SID","short":"$SHORT","ping":$NOW,"file":"$DISPLAY_PATH","tool":"$TOOL","status":"$STATUS","recent":[]}
EOF
  mv -f "$TMP" "$SESSIONS_DIR/$SID.json"
fi

# ── File collision guard (Edit/Write only) ────────────────────────────────────
# If another session touched this exact file in the last 5 seconds, deny the
# write to prevent silent clobber. Reads/Greps pass through.
COLLISION=""
LOCK_WINDOW=5

if [ "$HOOK" = "PreToolUse" ] && [ -n "$DISPLAY_PATH" ]; then
  case "$TOOL" in
    Edit|Write)
      for f in "$SESSIONS_DIR"/*.json; do
        [ -f "$f" ] || continue
        FNAME=$(basename "$f" .json)
        [ "$FNAME" = "$SID" ] && continue

        S_FILE=$(jq -r '.file // ""' "$f" 2>/dev/null) || continue
        [ "$S_FILE" != "$DISPLAY_PATH" ] && continue

        S_TOOL=$(jq -r '.tool // ""' "$f" 2>/dev/null) || continue
        # Only block if the other session was also writing (Edit/Write)
        case "$S_TOOL" in
          Edit|Write) ;;
          *) continue ;;
        esac

        S_PING=$(jq -r '.ping' "$f" 2>/dev/null) || continue
        S_AGO=$(( NOW - S_PING ))
        S_STATUS=$(jq -r '.status // "done"' "$f" 2>/dev/null) || continue

        if [ "$S_STATUS" = "active" ] && [ "$S_AGO" -le 120 ]; then
          # Sibling's Edit/Write tool call is still in progress — hard deny
          S_SHORT=$(jq -r '.short' "$f" 2>/dev/null) || continue
          COLLISION="Session $S_SHORT is actively editing $DISPLAY_PATH (tool call started ${S_AGO}s ago, still in progress). Re-read the file and retry."
          break
        elif [ "$S_AGO" -le "$LOCK_WINDOW" ]; then
          # Sibling recently finished editing — brief cooldown
          S_SHORT=$(jq -r '.short' "$f" 2>/dev/null) || continue
          COLLISION="Session $S_SHORT just finished editing $DISPLAY_PATH (${S_AGO}s ago). Re-read the file and retry."
          break
        fi
      done
      ;;
  esac
fi

# If collision detected, deny the tool call
if [ -n "$COLLISION" ]; then
  jq -n --arg reason "$COLLISION" '{hookSpecificOutput:{hookEventName:"PreToolUse",permissionDecision:"deny",permissionDecisionReason:$reason}}'
  exit 0
fi

# ── Message delivery: check for pending messages ─────────────────────────────
MESSAGES_DIR="$SESSIONS_DIR/messages"
mkdir -p "$MESSAGES_DIR"
PENDING_MSGS=""
MSG_STALE=300  # messages older than 5 min are cleaned up

for mf in "$MESSAGES_DIR"/*.json; do
  [ -f "$mf" ] || continue

  M_INFO=$(jq -r '{from:.from, to:.to, to_sid:(.to_sid // ""), msg:.msg, time:.time, from_sid:(.from_sid // "")}' "$mf" 2>/dev/null) || { rm -f "$mf"; continue; }

  M_TO=$(echo "$M_INFO" | jq -r '.to')
  M_TO_SID=$(echo "$M_INFO" | jq -r '.to_sid')
  M_FROM=$(echo "$M_INFO" | jq -r '.from')
  M_FROM_SID=$(echo "$M_INFO" | jq -r '.from_sid')
  M_MSG=$(echo "$M_INFO" | jq -r '.msg')
  M_TIME=$(echo "$M_INFO" | jq -r '.time')
  M_AGE=$(( NOW - M_TIME ))

  # Clean up stale messages
  if [ "$M_AGE" -gt "$MSG_STALE" ]; then
    rm -f "$mf"
    continue
  fi

  # Skip messages from self (check both full SID and short ID)
  [ -n "$M_FROM_SID" ] && [ "$M_FROM_SID" = "$SID" ] && continue
  [ "$M_FROM" = "$SHORT" ] && continue

  # Check if this message is for us
  DELIVER=false
  if [ "$M_TO" = "all" ]; then
    DELIVER=true
    # Don't delete global messages — other sessions need them too.
    # They'll expire via MSG_STALE.
  elif [ "$M_TO" = "$SHORT" ] || [ "$M_TO_SID" = "$SID" ]; then
    DELIVER=true
    # Targeted message — delete after delivery
    rm -f "$mf"
  fi

  if [ "$DELIVER" = true ]; then
    PENDING_MSGS="${PENDING_MSGS}
  - [from session $M_FROM, ${M_AGE}s ago]: $M_MSG"
  fi
done

# ── Query: scan for siblings ─────────────────────────────────────────────────
SIBLINGS=""
COUNT=1  # count self

for f in "$SESSIONS_DIR"/*.json; do
  [ -f "$f" ] || continue
  FNAME=$(basename "$f" .json)
  [ "$FNAME" = "$SID" ] && continue

  # Stale check via mtime (fast, no json parse)
  AGE=$(( NOW - $(stat -c %Y "$f") ))
  if [ "$AGE" -gt "$STALE_SEC" ]; then
    rm -f "$f"
    continue
  fi

  COUNT=$(( COUNT + 1 ))

  # Read sibling info (single jq call — extract basics + recent summaries)
  SIBLING_INFO=$(jq -r '
    def fmt_age($ago):
      if $ago < 60 then "\($ago)s ago"
      else "\($ago / 60 | floor)m ago"
      end;

    .short as $short |
    .file as $file |
    .tool as $tool |
    .ping as $ping |
    (.recent // []) as $recent |
    {short: $short, file: $file, tool: $tool, ping: $ping, status: (.status // ""), recent: $recent}
  ' "$f" 2>/dev/null) || continue

  S_SHORT=$(echo "$SIBLING_INFO" | jq -r '.short')
  S_FILE=$(echo "$SIBLING_INFO" | jq -r '.file // ""')
  S_TOOL=$(echo "$SIBLING_INFO" | jq -r '.tool // ""')
  S_PING=$(echo "$SIBLING_INFO" | jq -r '.ping // 0')
  S_AGO=$(( NOW - S_PING ))

  # Format age
  if [ "$S_AGO" -lt 60 ]; then
    AGO_STR="${S_AGO}s ago"
  else
    AGO_STR="$(( S_AGO / 60 ))m ago"
  fi

  S_STATUS=$(echo "$SIBLING_INFO" | jq -r '.status // ""')

  DETAIL=""
  [ -n "$S_FILE" ] && DETAIL=" → $S_FILE"
  [ -n "$S_TOOL" ] && DETAIL=" ($S_TOOL$DETAIL)"
  [ "$S_STATUS" = "active" ] && DETAIL="${DETAIL} [IN PROGRESS]"

  # Format recent summaries: deduplicate per-file (latest wins), show last 3
  RECENT_LINES=$(echo "$SIBLING_INFO" | jq -r '
    [.recent | to_entries[] | .value + {idx: .key}]
    | group_by(.file | split("/") | last)
    | map(max_by(.idx))
    | sort_by(-.idx)
    | .[:3]
    | .[]
    | "  \u2022 [\(.file | split("/") | last)] \(.summary)"
  ' 2>/dev/null)

  if [ -n "$RECENT_LINES" ]; then
    SIBLINGS="${SIBLINGS}
- session $S_SHORT${DETAIL}, ${AGO_STR}. Recent changes:
${RECENT_LINES}"
  else
    SIBLINGS="${SIBLINGS}
- session $S_SHORT${DETAIL}, ${AGO_STR}"
  fi
done

# ── No siblings and no messages? Exit silently ───────────────────────────────
[ -z "$SIBLINGS" ] && [ -z "$PENDING_MSGS" ] && exit 0

# ── Inject context ───────────────────────────────────────────────────────────
MSG="[SESSION AWARENESS] You are session $SHORT (1 of $COUNT active). Other sessions:${SIBLINGS}"

# Append pending messages if any
if [ -n "$PENDING_MSGS" ]; then
  MSG="${MSG}

[MESSAGES FOR YOU]:${PENDING_MSGS}

To reply, run: bash \"\$CLAUDE_PROJECT_DIR\"/.claude/hooks/send-message.sh <target_short_id|all> \"<message>\""
fi

MSG="${MSG}

If a file you just read has been modified by another session, do not investigate — just re-read it. If git status is unexpectedly clean, another session committed your work — check git log and move on."

# Output format depends on hook event
case "$HOOK" in
  PreToolUse)
    jq -n --arg ctx "$MSG" '{hookSpecificOutput:{hookEventName:"PreToolUse",permissionDecision:"allow",additionalContext:$ctx}}'
    ;;
  PostToolUse)
    jq -n --arg ctx "$MSG" '{hookSpecificOutput:{hookEventName:"PostToolUse",additionalContext:$ctx}}'
    ;;
  SessionStart|UserPromptSubmit)
    jq -n --arg ctx "$MSG" '{hookSpecificOutput:{hookEventName:"'"$HOOK"'",additionalContext:$ctx}}'
    ;;
  *)
    exit 0
    ;;
esac
